/**
 * Checks if a number is prime.
 * @param {number} n
 * @returns {boolean}
 */
function isPrime(n) {
    if (n <= 1) return false;
    if (n <= 3) return true;
    if (n % 2 === 0 || n % 3 === 0) return false;
    let i = 5;
    while (i * i <= n) {
        if (n % i === 0 || n % (i + 2) === 0) return false;
        i += 6;
    }
    return true;
}

/**
 * Finds the smallest non-negative increment to make a number prime.
 * @param {number} n
 * @returns {number}
 */
function minIncToPrime(n) {
    let current = n;
    while (!isPrime(current)) {
        current++;
    }
    return current - n;
}

/**
 * Finds the smallest non-negative increment to make a number non-prime (composite or 1).
 * @param {number} n
 * @returns {number}
 */
function minIncToNonPrime(n) {
    // 1 is non-prime (by convention for this problem context, although mathematically it's neither prime nor composite)
    // Since nums[i] >= 1, we check for 1 first.
    if (n === 1) return 0; // 1 is non-prime as per standard definition in prime factorization context for this problem (or we treat it as non-prime requirement satisfied if we can't increase it to composite)

    // Check if it's already non-prime (composite or 1)
    if (!isPrime(n)) return 0;

    // If it is prime, find the smallest increment to make it non-prime
    let current = n + 1;
    while (true) {
        if (!isPrime(current)) {
            return current - n;
        }
        current++;
    }
}

function solve(nums) {
    let totalOperations = 0;

    for (let i = 0; i < nums.length; i++) {
        const num = nums[i];

        if (i % 2 === 0) {
            // Even index: must be prime
            if (!isPrime(num)) {
                const cost = minIncToPrime(num);
                totalOperations += cost;
            }
            // If it is prime, cost is 0, so no action needed.
        } else {
            // Odd index: must be non-prime
            if (isPrime(num)) {
                const cost = minIncToNonPrime(num);
                totalOperations += cost;
            }
            // If it is non-prime, cost is 0, so no action needed.
        }
    }

    return totalOperations;
}

