import scala.collection.mutable

object Solution {
  // Sieve of Eratosthenes to precompute primes up to a limit
  private def sieve(limit: Int): BooleanArray = {
    val isPrime = new Array[Boolean](limit + 1) { _ => true }
    if (limit >= 0) isPrime(0) = false
    if (limit >= 1) isPrime(1) = false
    var p = 2
    while (p * p <= limit) {
      if (isPrime(p)) {
        var i = p * p
        while (i <= limit) {
          isPrime(i) = false
          i += p
        }
      }
      p += 1
    }
    isPrime
  }

  // Global storage for the sieve results, optimized for constraints
  private val MAX_VAL = 100000 + 1000 // Max nums[i] + small buffer
  private val primes = sieve(MAX_VAL)

  /**
   * Checks if a number is prime using the precomputed sieve.
   * Assumes n is within the precomputed range.
   */
  private def isPrime(n: Int): Boolean = {
    if (n < 0 || n >= primes.length) {
      // Fallback for safety, though constraints suggest this shouldn't be needed for the required operations
      if (n <= 1) false
      else {
        var i = 2
        while (i * i <= n) {
          if (n % i == 0) return false
          i += 1
        }
        true
      }
    } else {
      primes(n)
    }
  }

  /**
   * Finds the smallest non-negative increment to make a number prime.
   * Assumes n >= 1.
   */
  private def minIncToPrime(n: Int): Int = {
    var current = n
    while (!isPrime(current)) {
      current += 1
    }
    current - n
  }

  /**
   * Finds the smallest non-negative increment to make a number non-prime (composite or 1).
   * Assumes n >= 1.
   */
  private def minIncToNonPrime(n: Int): Int = {
    if (!isPrime(n)) {
      // Already non-prime (1 or composite)
      0
    } else {
      // It is prime, find the smallest increment to make it non-prime
      var current = n + 1
      while (true) {
        if (!isPrime(current)) {
          return current - n
        }
        current += 1
      }
    }
  }

  def nums(nums: Array[Long]): Long = {
    var totalOperations: Long = 0

    for (i <- 0 until nums.length) {
      // Convert Long to Int safely, given constraints (<= 10^5)
      val num = nums(i).toInt

      if (i % 2 == 0) {
